// src/pages/Plots.jsx

import axios from 'axios';
import { useEffect, useState } from 'react';

function Plots() {
  const [plots, setPlots] = useState([]);
  const [name, setName] = useState('');
  const [size, setSize] = useState('');
  const [plants, setPlants] = useState('');

  useEffect(() => {
    axios.get('http://localhost:5001/api/plots')
      .then(res => setPlots(res.data));
  }, []);

  const addPlot = async () => {
    if (!name || !size) {
      alert("Name and size are required");
      return;
    }

    const res = await axios.post('http://localhost:5001/api/plots', {
      name, size, plants
    });

    setPlots([...plots, res.data]);

    setName('');
    setSize('');
    setPlants('');
  };

  const deletePlot = async (id) => {
    await axios.delete(`http://localhost:5001/api/plots/${id}`);
    setPlots(plots.filter(p => p._id !== id));
  };

  const updatePlot = async (id, status) => {
    const res = await axios.put(`http://localhost:5001/api/plots/${id}`, { status });
    setPlots(plots.map(p => p._id === id ? res.data : p));
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1 style={{paddingBottom: "30px"}}><b>Plot Management</b></h1>

      {/* Form */}
      <div style={{
        marginBottom: "20px",
        padding: "15px",
        border: "1px solid #ddd",
        borderRadius: "8px",
        backgroundColor: "#f9fafb",
        display: "flex",
        alignItems: "center",
        gap: "10px"
      }}>
        <input
          value={name}
          placeholder="Plot name"
          onChange={(e) => setName(e.target.value)}
          style={{
            padding: "8px",
            border: "1px solid #ccc",
            borderRadius: "5px",
            outline: "none"
          }}
        />

        <input
          value={size}
          placeholder="Size"
          onChange={(e) => setSize(e.target.value)}
          style={{
            padding: "8px",
            border: "1px solid #ccc",
            borderRadius: "5px",
            outline: "none"
          }}
        />

        <input
          value={plants}
          placeholder="Plants"
          onChange={(e) => setPlants(e.target.value)}
          style={{
            padding: "8px",
            border: "1px solid #ccc",
            borderRadius: "5px",
            outline: "none"
          }}
        />

        <button
          onClick={addPlot}
          style={{
            padding: "8px 14px",
            backgroundColor: "#16a34a",
            color: "white",
            border: "none",
            borderRadius: "5px",
            cursor: "pointer"
          }}
        >
          + Add Plot
        </button>
      </div>
<div style={{textAlign: "left"}}>
      {/* Table */}
      <table border="1" cellPadding="10" style={{ width: "100%", borderCollapse: "collapse", BackgroundColor: "white",borderRadius: "5px", overflow: "hidden", boxShadow: "0 2px 10px 0 rgba(0, 0, 0, 0.5)"}}>
        <thead>
          <tr>
            <th>Name</th>
            <th>Size</th>
            <th>Plants</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>

        <tbody>
          {plots.map(plot => (
            <tr key={plot._id}>
              <td>{plot.name}</td>
              <td>{plot.size}</td>
              <td>{plot.plants}</td>

              <td>
                <select
                  value={plot.status}
                  onChange={(e) => updatePlot(plot._id, e.target.value)}
                >
                  <option value="Available">Available</option>
                  <option value="Occupied">Occupied</option>
                </select>
              </td>

              <td>
                <button style={{backgroundColor: "#FF0000", color: "white", border: "none", padding: "8px 14px", borderRadius: "5px", cursor: "pointer"}} onClick={() => deletePlot(plot._id)}>
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table></div>
    </div>
  );
}

export default Plots;
